import React, {type FC, type MouseEventHandler, useRef} from "react";
import {Button, Flex} from "../../Molecules";
// import {OverlayPanel} from "primereact/overlaypanel";
// import {TimesIcon} from "primereact/icons/times";
import type {IPopoverProps} from "@lmb-it/kitsconcerto-types";

const CustomPopover: FC<IPopoverProps> = ({
  children,
  label,
  onPopoverClosed,
  onPopoverOpened,
  closeButton = false,
}) => {
  const op = useRef<any>(null);

  const toggle:MouseEventHandler<any> = (event) => {
    op.current?.toggle(event);
  };
  return (
    <>
      {typeof label == "string" && <Button onClick={toggle}>{label}</Button>}
      {typeof label != "string" && <Flex onClick={toggle}>{label}</Flex>}

      {/*<OverlayPanel
        closeIcon={<TimesIcon />}
        showCloseIcon={closeButton}
        ref={op}
        onShow={() => {
          onPopoverOpened && onPopoverOpened();
        }}
        onHide={() => {
          onPopoverClosed && onPopoverClosed();
        }}
      >
        {typeof children == "function"
          ? children({ onClose: () => op.current?.hide() })
          : children}
      </OverlayPanel>*/}
    </>
  );
};

export default CustomPopover;
